mapper.select:

group by c.id, c.name, c.slug, c.description, c.sort_order
order by c.sort_order, c.id
limit #{limit} offset #{offset}

mapper.update:
update categories
set name = #{name}, slug = #{slug}, description = #{description}, sort_order = #{sort}, updated_at = current_timestamp
where id = #{id}

